-- ============================================================
-- SEED: shipper_contacts - 12,380 shipping companies
-- Generated for AuditDNA CRM
-- Run in pgAdmin on database: auditdna
-- ============================================================

CREATE TABLE IF NOT EXISTS shipper_contacts (
  id               SERIAL PRIMARY KEY,
  name             VARCHAR(255),
  company          VARCHAR(255),
  contact          VARCHAR(255),
  email            VARCHAR(255),
  phone            VARCHAR(50),
  state            VARCHAR(20),
  city             VARCHAR(100),
  region           VARCHAR(100),
  address_city     VARCHAR(100),
  address_country  VARCHAR(100) DEFAULT 'USA',
  lead_temperature VARCHAR(20) DEFAULT 'COLD',
  lead_status      VARCHAR(30) DEFAULT 'NEW',
  status           VARCHAR(30) DEFAULT 'Active',
  source           VARCHAR(100),
  notes            TEXT,
  priority         VARCHAR(20) DEFAULT 'NORMAL',
  created_at       TIMESTAMP DEFAULT NOW(),
  updated_at       TIMESTAMP DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_shipper_temp ON shipper_contacts(lead_temperature);
CREATE INDEX IF NOT EXISTS idx_shipper_state ON shipper_contacts(state);
CREATE INDEX IF NOT EXISTS idx_shipper_country ON shipper_contacts(address_country);
CREATE INDEX IF NOT EXISTS idx_shipper_source ON shipper_contacts(source);


























-- Set realistic temperature distribution
UPDATE shipper_contacts SET lead_temperature = 'HOT' WHERE id IN (
  SELECT id FROM shipper_contacts ORDER BY RANDOM() LIMIT 620);

UPDATE shipper_contacts SET lead_temperature = 'WARM'
  WHERE lead_temperature = 'COLD' AND id IN (
  SELECT id FROM shipper_contacts WHERE lead_temperature = 'COLD' ORDER BY RANDOM() LIMIT 3340);

SELECT COUNT(*) as total_shippers FROM shipper_contacts;
SELECT lead_temperature, COUNT(*) FROM shipper_contacts GROUP BY lead_temperature ORDER BY 1;

